artist_stats = train.groupby('track_artist').agg(
    mean_popularity=('track_popularity', 'mean')
).reset_index()
def categorize_popularity(mean_pop):
    if mean_pop >= 60:
        return 'Popular'
    elif mean_pop >= 30:
        return 'Semi-popular'
    else:
        return 'Not Popular'
artist_stats['artist_popularity_category'] = artist_stats['mean_popularity'].apply(categorize_popularity)
train = train.merge(artist_stats[['track_artist', 'artist_popularity_category']], on='track_artist', how='left')
print(train[['track_artist', 'track_popularity', 'artist_popularity_category']].head())

